import{_ as t,o as i,c as s,ao as a}from"./chunks/framework.C2uOknPB.js";const c=JSON.parse('{"title":"Building","description":"","frontmatter":{},"headers":[],"relativePath":"guide/building.md","filePath":"guide/building.md","lastUpdated":null}'),n={name:"guide/building.md"};function l(d,e,o,h,r,p){return i(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="Building" tabindex="-1">Building <a class="header-anchor" href="#Building" aria-label="Permalink to &quot;Building {#Building}&quot;">​</a></h1><p>ParselTongue offers two build entry points.</p><h2 id="build_wheel-—-a-self-contained,-pip-installable-wheel" tabindex="-1"><code>build_wheel</code> — a self-contained, pip-installable wheel <a class="header-anchor" href="#build_wheel-—-a-self-contained,-pip-installable-wheel" aria-label="Permalink to &quot;`build_wheel` — a self-contained, pip-installable wheel {#build_wheel-—-a-self-contained,-pip-installable-wheel}&quot;">​</a></h2><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build_wheel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mymod.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; version </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;0.2.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, outdir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;dist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Produces <code>dist/mymod-0.2.0-&lt;pytag&gt;.whl</code> that bundles the Julia runtime. Install it with <code>pip</code> on any compatible machine — <strong>no Julia required</strong>. This is what you ship.</p><p>The wheel layout:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mymod/__init__.py                     re-exports the compiled extension</span></span>\n<span class="line"><span>mymod/_mymod.&lt;EXT_SUFFIX&gt;             the extension (PyInit__mymod)</span></span>\n<span class="line"><span>mymod/julia/lib/libjulia.so.1.x       Julia runtime, original relative layout</span></span>\n<span class="line"><span>mymod/julia/lib/julia/…               preserved so the libs resolve each other</span></span>\n<span class="line"><span>mymod-&lt;ver&gt;.dist-info/{METADATA,WHEEL,RECORD}</span></span></code></pre></div><h2 id="build_extension-—-just-the-extension-.so" tabindex="-1"><code>build_extension</code> — just the extension <code>.so</code> <a class="header-anchor" href="#build_extension-—-just-the-extension-.so" aria-label="Permalink to &quot;`build_extension` — just the extension `.so` {#build_extension-—-just-the-extension-.so}&quot;">​</a></h2><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build_extension</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mymod.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; outdir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Produces only <code>build/mymod.&lt;EXT_SUFFIX&gt;</code> and does <strong>not</strong> bundle libjulia — the surrounding environment must provide it (its rpath points at the Julia that built it). Useful for local iteration and testing.</p><h2 id="Options" tabindex="-1">Options <a class="header-anchor" href="#Options" aria-label="Permalink to &quot;Options {#Options}&quot;">​</a></h2><p>Both functions accept:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Keyword</th><th style="text-align:right;">Default</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>mod_name</code></td><td style="text-align:right;">from <code>@pymodule</code>, else the file&#39;s base name</td><td style="text-align:right;">Python module name</td></tr><tr><td style="text-align:right;"><code>outdir</code></td><td style="text-align:right;">next to the source file</td><td style="text-align:right;">output directory</td></tr><tr><td style="text-align:right;"><code>trim</code></td><td style="text-align:right;"><code>:safe</code></td><td style="text-align:right;"><code>:safe</code> errors on dynamic dispatch; <code>:unsafe</code> / <code>:unsafe_warn</code> relax it</td></tr><tr><td style="text-align:right;"><code>python</code></td><td style="text-align:right;"><code>&quot;python3&quot;</code></td><td style="text-align:right;">the Python interpreter to target</td></tr><tr><td style="text-align:right;"><code>verbose</code></td><td style="text-align:right;"><code>false</code></td><td style="text-align:right;">print the juliac and link commands</td></tr></tbody></table><p><code>build_wheel</code> additionally takes <code>version</code> (default <code>&quot;0.1.0&quot;</code>).</p><h3 id="Trim-modes" tabindex="-1">Trim modes <a class="header-anchor" href="#Trim-modes" aria-label="Permalink to &quot;Trim modes {#Trim-modes}&quot;">​</a></h3><p><code>--trim=safe</code> (the default) makes juliac <strong>error at build time</strong> if an exported code path needs dynamic dispatch — the failure is reported as a Julia stack-frame, before any wheel is produced. If you hit one, the usual fix is to make the offending function type-stable. As an escape hatch:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">build_wheel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mymod.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; trim </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :unsafe_warn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># warns instead of erroring</span></span></code></pre></div><p>See the <a href="/ParselTongue.jl/dev/reference/api#Building">API Reference</a> for the full docstrings of <a href="/ParselTongue.jl/dev/reference/api#ParselTongue.build_extension"><code>build_extension</code></a> and <a href="/ParselTongue.jl/dev/reference/api#ParselTongue.build_wheel"><code>build_wheel</code></a>.</p>',18)])])}const g=t(n,[["render",l]]);export{c as __pageData,g as default};
